mapper.select:
SELECT * FROM path_chapter 
WHERE path_id = #{pathId} 
ORDER BY order_num ASC

mapper.update:
UPDATE path_chapter 
SET name = #{name}, order_num = #{orderNum}, description = #{description}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT * FROM path_level 
WHERE chapter_id = #{chapterId} 
ORDER BY order_num ASC

SELECT * FROM user_path_progress 
WHERE user_id = #{userId}
ORDER BY update_time DESC

SELECT * FROM assessment_question 
WHERE language = #{language} AND direction = #{direction}
ORDER BY RAND() 
LIMIT #{limit}

SELECT * FROM user_assessment 
WHERE user_id = #{userId}
ORDER BY create_time DESC
